package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getAllowMissingColumnNames(), "Default should not allow missing column names");

        CSVFormat updated = original.withAllowMissingColumnNames(true);
        assertNotNull(updated);
        assertTrue(updated.getAllowMissingColumnNames(), "withAllowMissingColumnNames(true) should set allowMissingColumnNames to true");

        // Original should remain unchanged (immutability)
        assertFalse(original.getAllowMissingColumnNames(), "Original instance should remain unchanged");

        // Also test the boolean argument variant explicitly
        CSVFormat updatedFalse = original.withAllowMissingColumnNames(false);
        assertNotNull(updatedFalse);
        assertFalse(updatedFalse.getAllowMissingColumnNames(), "withAllowMissingColumnNames(false) should set allowMissingColumnNames to false");
    }
}
